use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

// Define a state for Dijkstra's algorithm: (cost, node)
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    node: usize,
}

// Implement Ord and PartialOrd for use in BinaryHeap (Min-Heap simulation)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice that we flip the order to make BinaryHeap act as a Min-Heap
        other.cost.cmp(&self.cost)
            .then_with(|| self.node.cmp(&other.node))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Structure to hold edge information
struct Edge {
    to: usize,
    weight: i64,
}

// Dijkstra's algorithm implementation
// Returns a vector where dist[i] is the shortest distance from start_node to i.
fn dijkstra(n: usize, adj: &Vec<Vec<Edge>>, start_node: usize) -> Vec<i64> {
    const INF: i64 = i64::MAX / 2; // Use a large number for infinity to prevent overflow during addition
    let mut dist = vec![INF; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, node: start_node });

    while let Some(State { cost: d, node: u }) = heap.pop() {
        if d > dist[u] {
            continue;
        }

        for edge in &adj[u] {
            let v = edge.to;
            let weight = edge.weight;
            let new_dist = d + weight;

            if new_dist < dist[v] {
                dist[v] = new_dist;
                heap.push(State { cost: new_dist, node: v });
            }
        }
    }
    dist
}


fn solve(n: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n = n as usize;
    let prices = prices;
    let roads = roads;
    const INF: i64 = i64::MAX / 2;

    // 1. Build two adjacency lists: one for no apples (cost) and one for with apples (cost * tax)

    // Adjacency list for travel WITHOUT apples (weight = cost_i)
    let mut adj_no_apples: Vec<Vec<Edge>> = vec![Vec::new(); n];

    // Adjacency list for travel WITH apples (weight = cost_i * tax_i)
    let mut adj_with_apples: Vec<Vec<Edge>> = vec![Vec::new(); n];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // --- Travel WITHOUT apples (Cost = cost) ---

        // u -> v
        adj_no_apples[u].push(Edge { to: v, weight: cost });
        // v -> u (Bidirectional)
        adj_no_apples[v].push(Edge { to: u, weight: cost });

        // --- Travel WITH apples (Cost = cost * tax) ---
        let taxed_cost = cost * tax;

        // u -> v
        adj_with_apples[u].push(Edge { to: v, weight: taxed_cost });
        // v -> u (Bidirectional)
        adj_with_apples[v].push(Edge { to: u, weight: taxed_cost });
    }

    // 2. Calculate All-Pairs Shortest Path (APSP) for both scenarios.

    // Dist_NoApples[i][j]: Shortest path i -> j without apples
    let mut dist_no_apples: Vec<Vec<i64>> = vec![vec![INF; n]; n];
    for i in 0..n {
        let dists = dijkstra(n, &adj_no_apples, i);
        for j in 0..n {
            dist_no_apples[i][j] = dists[j];
        }
    }

    // Dist_WithApples[j][i]: Shortest path j -> i with apples (for return trip)
    // Note the indexing: we need J -> I, so we store Dist_WithApples[J][I]
    let mut dist_with_apples: Vec<Vec<i64>> = vec![vec![INF; n]; n];
    for j in 0..n {
        let dists = dijkstra(n, &adj_with_apples, j);
        for i in 0..n {
            dist_with_apples[j][i] = dists[i];
        }
    }

    // 3. Calculate final answer for each shop i
    let mut ans: Vec<i64> = vec![0; n];

    for i in 0..n {
        // Option 1: Buy directly at i
        let mut min_cost = prices[i];

        // Option 2: Go to j, buy at j, return to i
        for j in 0..n {
            if i == j {
                continue;
            }

            // Travel I -> J (Empty hand, cost_only)
            let travel_to_j_cost = dist_no_apples[i][j];

            // Travel J -> I (Loaded apple, cost_taxed)
            let travel_back_j_to_i_cost = dist_with_apples[j][i];

            if travel_to_j_cost == INF || travel_back_j_to_i_cost == INF {
                continue;
            }

            // Total cost = Travel(I->J, no) + Price(J) + Travel(J->I, taxed)
            let total_cost = travel_to_j_cost + prices[j] + travel_back_j_to_i_cost;

            min_cost = min_cost.min(total_cost);
        }
        ans[i] = min_cost;
    }

    ans
}
