 * @param {number} n The number of shops.
 * @param {Array<number>} prices The price of apples at each shop.
 * @param {Array<Array<number>>} roads The road connections: [u, v, cost, tax].
 * @returns {Array<number>} The minimum cost for each shop to get apples.
 */
function solve(n, prices, roads) {
    // 1. Build adjacency lists for two types of travel:
    //    - Travel without apples (Cost = cost)
    //    - Travel with apples (Cost = cost * tax)

    // Since roads are bidirectional, we store edges for both directions.
    // We need to map the roads to indices for easier reference later.
    const numRoads = roads.length;
    const adj_no_apples = Array.from({ length: n }, () => []);
    const adj_with_apples = Array.from({ length: n }, () => []);
    const edge_weights = [];

    for (let i = 0; i < numRoads; i++) {
        const [u, v, cost, tax] = roads[i];

        // Edge index i is used to represent this road connection

        // Travel WITHOUT apples (cost)
        // Road u -> v (no apples)
        adj_no_apples[u].push(i);
        // Road v -> u (no apples)
        adj_no_apples[v].push(i);

        // Road u -> v (with apples)
        adj_with_apples[u].push(i);
        // Road v -> u (with apples)
        adj_with_apples[v].push(i);

        // Store weights for road i: [neighbor, weight]
        // Road i connects u and v. We store both directions.
        // Weight for u <-> v when NOT carrying apples
        edge_weights.push([v, cost]); // For u -> v
        edge_weights.push([u, cost]); // For v -> u

        // Weight for u <-> v when CARRYING apples
        // Tax multiplier is applied to cost
        const taxCost = cost * tax;
        edge_weights.push([v, taxCost]); // For u -> v
        edge_weights.push([u, taxCost]); // For v -> u
    }

    // Reorganize edge_weights structure to be accessible by node and type.
    // We need four sets of shortest paths:
    // 1. Shortest path from any J to I WITHOUT apples (To get to J)
    // 2. Shortest path from I back to any J WITH apples (To return to I)

    // --- Part 1: Calculate Shortest Path to any node J (Empty Hand) ---
    // We need min(Dist(J -> I)) for all J.
    // This is equivalent to running Dijkstra from all potential sources J 
    // on the "no apples" graph, but since we want min_J(Dist(J->I)), 
    // this is equivalent to running Dijkstra *on the reverse graph* from I.
    // Since the graph is undirected, the reverse graph is the same.

    // shortest_to_I[i] = min_j (shortest path cost from j to i without apples)
    let shortest_to_I = new Array(n).fill(Infinity);

    // Run Dijkstra starting from *every* node J on the "no apples" graph
    // to find the shortest path from J to all other nodes I.
    // Then, shortest_to_I[I] = min_J(dist[I] from J)

    for (let j = 0; j < n; j++) {
        // Dijkstra on the graph where edges have weight 'cost'
        // We need to pass the structure appropriate for Dijkstra:
        // adj: [neighbor_index_in_weights], weights: [neighbor, weight]
        const dist_from_j = dijkstra(n, adj_no_apples, edge_weights, j);

        for (let i = 0; i < n; i++) {
            shortest_to_I[i] = Math.min(shortest_to_I[i], dist_from_j[i]);
        }
    }


    // --- Part 2: Calculate Shortest Path from node J (Loaded Apple) ---
    // We need min(Dist(I -> J)) for all J, where travel I->J is with apples.
    // This is equivalent to running Dijkstra from I on the "with apples" graph.

    // shortest_from_I[i] = min_j (shortest path cost from i to j with apples)
    // Note: The path must be from I (start) to J (purchase location).
    let shortest_from_I = new Array(n).fill(Infinity);

    // Run Dijkstra starting from *every* node I on the "with apples" graph
    // to find the shortest path from I to all other nodes J.

    for (let i = 0; i < n; i++) {
        // Dijkstra on the graph where edges have weight 'cost * tax'
        const dist_from_i = dijkstra(n, adj_with_apples, edge_weights, i);

        // For a fixed start node I, the required value is min_J (dist_from_i[J])
        // But wait, we need ans[i] = min(prices[i], min_j (Dist(i->j, taxed) + prices[j] + Dist(j->i, taxed))).
        // The path I->J (empty hand) cost is shortest_to_I[J].
        // The path J->I (loaded) cost is shortest_from_J[I].

        // Let's re-examine the required path:
        // 1. Start at I (Empty hand) -> Go to J (Empty hand). Cost: Dist(I->J, cost_only).
        // 2. Buy at J. Cost: prices[J].
        // 3. Return from J (Loaded) -> Back to I (Loaded). Cost: Dist(J->I, cost_taxed).

        // Since the problem states: "Path to J (empty hand) and path back from J (loaded) can be different."

        // Cost = Dist(I->J, cost_only) + prices[J] + Dist(J->I, cost_taxed)

        // 1. Dist(I->J, cost_only): Shortest path from I to J without apples.
        // 2. Dist(J->I, cost_taxed): Shortest path from J to I with apples.

        // We need:
        // A. Dist_NoApples[I][J]: Shortest path I->J without apples.
        // B. Dist_WithApples[J][I]: Shortest path J->I with apples.

        // --- Recalculate A: All-Pairs Shortest Path (APSP) for No Apples ---
        const Dist_NoApples = Array.from({ length: n }, () => new Array(n).fill(Infinity));
        for (let startNode = 0; startNode < n; startNode++) {
            const dist_from_start = dijkstra(n, adj_no_apples, edge_weights, startNode);
            for (let endNode = 0; endNode < n; endNode++) {
                Dist_NoApples[startNode][endNode] = dist_from_start[endNode];
            }
        }

        // --- Recalculate B: APSP for With Apples ---
        const Dist_WithApples = Array.from({ length: n }, () => new Array(n).fill(Infinity));
        for (let startNode = 0; startNode < n; startNode++) {
            const dist_from_start = dijkstra(n, adj_with_apples, edge_weights, startNode);
            for (let endNode = 0; endNode < n; endNode++) {
                Dist_WithApples[startNode][endNode] = dist_from_start[endNode];
            }
        }
    }

    // 3. Calculate final answer for each shop i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let min_cost = prices[i];

        // Option 2: Go to j, buy at j, return to i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const travel_to_j_cost = Dist_NoApples[i][j]; // I -> J, no apples
            const travel_back_j_to_i_cost = Dist_WithApples[j][i]; // J -> I, with apples

            // Check if paths exist
            if (travel_to_j_cost === Infinity || travel_back_j_to_i_cost === Infinity) {
                continue;
            }

            // Total cost = Travel(I->J, no) + Price(J) + Travel(J->I, taxed)
            const total_cost = travel_to_j_cost + prices[j] + travel_back_j_to_i_cost;

            min_cost = Math.min(min_cost, total_cost);
        }
        ans[i] = min_cost;
    }

    return ans;
}

