// Define a state for Dijkstra's priority queue
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement Ord for min-heap behavior (we use reverse ordering for min-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the order is reversed to make BinaryHeap act as a min-heap
        other.cost.cmp(&self.cost)
    }
}

// Implement PartialOrd
impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

