use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Define a struct for the priority queue elements
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement comparison traits for min-heap behavior in Rust's BinaryHeap (which is a max-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the order is reversed to make it a min-heap based on cost
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Dijkstra's algorithm implementation
// Finds shortest paths from a startNode using given graph structure (adj and weights)
// weights structure: Vec<Vec<(neighbor, weight)>>
fn dijkstra(n: usize, adj: &Vec<Vec<usize>>, weights: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
    let mut dist: Vec<i64> = vec![i64::MAX; n];
    dist[start_node] = 0;

    // Min-Heap priority queue: stores State { cost, position }
    let mut heap = BinaryHeap::new();
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position: u }) = heap.pop() {
        if cost > dist[u] {
            continue;
        }

        // Iterate over the road indices connected to u
