// Implement comparison traits for min-heap behavior in Rust's BinaryHeap (which is a max-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the order is reversed to make it a min-heap based on cost
        other.cost.cmp(&self.cost)
    }
}

